// Arma la lista de URLs a descargar según la config de paginación del sitio.
const src = $json;
const cfg = src.config ?? {};
const pag = cfg.pagination ?? {};

const listUrl = new URL(cfg.list_url ?? '/', src.base_url).href;
const urls = [];

if (pag.enabled) {
  const maxPages = Number(pag.max_pages ?? 1);
  const param = pag.param ?? 'page';
  const start = Number(pag.start ?? 1);
  for (let i = 0; i < maxPages; i++) {
    const u = new URL(listUrl);
    u.searchParams.set(param, String(start + i));
    urls.push(u.href);
  }
} else {
  urls.push(listUrl);
}

return { json: { ...src, urls } };

// Parseo genérico guiado por los selectores de sources.config.
// Requiere NODE_FUNCTION_ALLOW_EXTERNAL=cheerio en la instancia de n8n.
const cheerio = require('cheerio');

const src = $('Cuando el orquestador llama').first().json;
const cfg = src.config ?? {};
const sel = cfg.selectors ?? {};
const baseUrl = src.base_url;
const defaultCurrency = cfg.currency_default ?? 'PYG';

if (!sel.item) {
  throw new Error(`La fuente "${src.name}" no tiene definido selectors.item en su config.`);
}

// Convención "selector@atributo": con @ extrae el atributo, sin @ extrae el texto.
function pick($, $scope, spec) {
  if (!spec) return null;
  const [selector, attr] = spec.split('@');
  const node = selector ? $scope.find(selector).first() : $scope;
  if (!node || node.length === 0) return null;
  const val = attr ? node.attr(attr) : node.text();
  return val ? val.replace(/\s+/g, ' ').trim() : null;
}

function toAbsolute(url) {
  if (!url) return null;
  try { return new URL(url, baseUrl).href; } catch { return null; }
}

// "Gs. 1.250.000" -> 1250000 PYG | "USD 1,299.00" -> 1299.00 USD
function parsePrice(raw) {
  if (!raw) return { price: null, currency: defaultCurrency };

  const hasGuarani = /(gs|₲|g\$)/i.test(raw);
  const hasDollar = /(us\$|usd|\$)/i.test(raw);
  const currency = hasGuarani ? 'PYG' : (hasDollar ? 'USD' : defaultCurrency);

  const digits = raw.replace(/[^0-9.,]/g, '');
  if (!digits) return { price: null, currency };

  // Si el último separador tiene exactamente 2 dígitos detrás es el decimal;
  // si no, todos los separadores son de miles (formato PYG: 1.250.000).
  const lastSep = Math.max(digits.lastIndexOf('.'), digits.lastIndexOf(','));
  let price;
  if (lastSep !== -1 && digits.length - lastSep - 1 === 2) {
    const intPart = digits.slice(0, lastSep).replace(/[.,]/g, '');
    price = Number(`${intPart || '0'}.${digits.slice(lastSep + 1)}`);
  } else {
    price = Number(digits.replace(/[.,]/g, ''));
  }

  return { price: Number.isFinite(price) ? price : null, currency };
}

const out = [];
const vistos = new Set();

for (const item of $input.all()) {
  const html = item.json.html;
  if (!html || typeof html !== 'string') continue;

  const $ = cheerio.load(html);

  $(sel.item).each((_, el) => {
    const $el = $(el);

    const name = pick($, $el, sel.title);
    const productUrl = toAbsolute(pick($, $el, sel.url));

    // Sin nombre o sin link no sirve: el agente no puede ofrecerlo.
    if (!name || !productUrl) return;

    // La URL del producto es el id estable dentro de esta fuente.
    if (vistos.has(productUrl)) return;
    vistos.add(productUrl);

    const { price, currency } = parsePrice(pick($, $el, sel.price));

    out.push({
      json: {
        source_id: src.source_id,
        external_id: productUrl,
        name,
        description: pick($, $el, sel.description),
        category: pick($, $el, sel.category) ?? cfg.category_default ?? null,
        price,
        currency,
        image_url: toAbsolute(pick($, $el, sel.image)),
        product_url: productUrl,
        seller_name: src.name,
        location: cfg.location ?? 'Ciudad del Este',
      },
    });
  });
}

return out;
